import json

# Load citations
file_path_citations = locals()['var_function-call-17184037719659309695']
with open(file_path_citations, 'r') as f:
    citations = json.load(f)

# Load DB filenames
file_path_db = locals()['var_function-call-15124095079000885129']
with open(file_path_db, 'r') as f:
    db_docs = json.load(f)

db_filenames = set(d['filename'] for d in db_docs)

# Find intersection
valid_filenames = []
for c in citations:
    fname = c['title'] + ".txt"
    if fname in db_filenames:
        valid_filenames.append(fname)

# Construct query
query = {
    "collection": "paper_docs",
    "filter": {
        "filename": {"$in": valid_filenames}
    },
    "projection": {"filename": 1, "text": 1}
}

print("__RESULT__:")
print(json.dumps(query))

